import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import Card from '../../../shared/components/Card/Card';
import './TrendChart.css';

const TrendChart = ({ transactions }) => {
  // Find the most recent month that actually has transactions
  let targetYear, targetMonth;

  if (transactions.length > 0) {
    // Pick the year/month from the most recent transaction
    const dates = transactions
      .filter((t) => t.date)
      .map((t) => {
        const parts = String(t.date).split('-');
        return { year: parseInt(parts[0]), month: parseInt(parts[1]) - 1 };
      })
      .sort((a, b) => b.year - a.year || b.month - a.month);
    targetYear  = dates[0].year;
    targetMonth = dates[0].month;
  } else {
    const now = new Date();
    targetYear  = now.getFullYear();
    targetMonth = now.getMonth();
  }

  const weeks = [
    { label: 'Week 1', income: 0, expenses: 0 },
    { label: 'Week 2', income: 0, expenses: 0 },
    { label: 'Week 3', income: 0, expenses: 0 },
    { label: 'Week 4', income: 0, expenses: 0 },
  ];

  transactions.forEach((t) => {
    if (!t.date) return;
    const parts = String(t.date).split('-');
    const year  = parseInt(parts[0]);
    const month = parseInt(parts[1]) - 1;
    const day   = parseInt(parts[2]);

    if (month !== targetMonth || year !== targetYear) return;

    const weekIndex = Math.min(Math.floor((day - 1) / 7), 3);
    if (t.type === 'credit') {
      weeks[weekIndex].income += t.amount;
    } else {
      weeks[weekIndex].expenses += Math.abs(t.amount);
    }
  });

  const d = new Date(targetYear, targetMonth, 1);
  const monthLabel = d.toLocaleString('en-IN', { month: 'long', year: 'numeric' });

  return (
    <Card className="trend-chart">
      <h2 className="chart-title">Income vs Expenses — {monthLabel}</h2>
      <ResponsiveContainer width="100%" height={230}>
        <BarChart data={weeks} margin={{ top: 5, right: 5, bottom: 0, left: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="var(--color-border)" />
          <XAxis dataKey="label" tick={{ fill: 'var(--color-text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} />
          <YAxis tickFormatter={(v) => `₹${(v/1000).toFixed(0)}k`} tick={{ fill: 'var(--color-text-muted)', fontSize: 10 }} axisLine={false} tickLine={false} />
          <Tooltip
            contentStyle={{ background: 'var(--color-surface-2)', border: '1px solid var(--color-border)', borderRadius: '10px', fontSize: '0.8rem' }}
            formatter={(v) => [`₹${v.toLocaleString('en-IN')}`]}
          />
          <Legend wrapperStyle={{ fontSize: '0.78rem' }} />
          <Bar dataKey="income"   fill="#06d6a0" radius={[4,4,0,0]} name="Income"   />
          <Bar dataKey="expenses" fill="#f43f5e" radius={[4,4,0,0]} name="Expenses" />
        </BarChart>
      </ResponsiveContainer>
    </Card>
  );
};

export default TrendChart;
